    21→  private async getOne(id: string): Promise<AddressEntity> {
    22→    const addressRepository = this.txHost.tx.getRepository(AddressEntity);
    23→
    24→    const address = await addressRepository.findOne({
    25→      where: { id },
    26→      relations: ['country'],
    27→    });
    28→
    29→    return address!;
    30→  }
    31→
    32→  async upsert(id: string | undefined, dto: AddressDto) {
    33→    const addressRepository = this.txHost.tx.getRepository(AddressEntity);
    34→    const countryRepository = this.txHost.tx.getRepository(CountryEntity);
    35→
    36→    const country = await countryRepository.findOne({
    37→      where: { id: dto.countryId },
    38→    });
    39→
    40→    if (!country) {
    41→      throw new NotFoundException('Country not found');
    42→    }
    43→
    44→    if (!country.enabled) {
    45→      throw new BadRequestException('Country is not supported');
    46→    }
    47→
    48→    return addressRepository.save({
    49→      id,
    50→      ...dto,
    51→    });
    52→  }
    53→
    54→  async delete(id: string) {
    55→    const addressRepository = this.txHost.tx.getRepository(AddressEntity);
    56→
    57→    await addressRepository.delete({ id });
    58→  }
    59→
    60→  // utility
    61→  async getByUserId(userId: string, throwIfNotFound = true) {
    62→    const addressRepository = this.txHost.tx.getRepository(AddressEntity);
    63→
    64→    const rowAddress = await addressRepository.findOne({
    65→      where: { userId },
    66→    });
    67→
    68→    if (!rowAddress) {
    69→      if (throwIfNotFound) {
    70→        throw new NotFoundException('Address not found');
    71→      } else {
    72→        return null;
    73→      }
    74→    }
    75→
    76→    return this.getOne(rowAddress.id);
    77→  }
    78→}
