@Entity({ name: 'address' })
export class AddressEntity extends BaseEntity {
  @OneToOne(() => UserEntity, { onDelete: 'CASCADE', nullable: true })
  @JoinColumn({ name: 'user_id', referencedColumnName: 'id' })
