  @ManyToOne(() => CountryEntity, { onDelete: 'CASCADE', nullable: false })
  @JoinColumn({ name: 'country_id', referencedColumnName: 'id' })
  country: CountryEntity;

  @Index('idx_user_country_id')
  @Column({ type: 'uuid', name: 'country_id' })
